fn manage_print_queue(
    pending_jobs: VecDeque<(String, i32)>,
    printer_status: HashMap<String, bool>,
) -> (
    VecDeque<(String, i32)>,
    HashMap<String, bool>,
    BTreeSet<String>,
    [i32; 5],
) {
    let mut updated_queue = VecDeque::new();
    let mut updated_status = HashMap::new();
    let mut maintenance_set = BTreeSet::new();
    let mut completed_jobs: [i32; 5] = [0; 5];

    for (printer, job) in pending_jobs {
        if let Some(status) = printer_status.get_mut(&printer) {
            if *status {
                updated_queue.push_back((printer.clone(), job));
                *status = true;
            } else {
                maintenance_set.insert(printer.clone());
            }
        }
    }

    for (printer, status) in printer_status {
        if status {
            let mut index = 0;
            while index < 5 && completed_jobs[index] != 0 {
                index += 1;
            }
            if index < 5 {
                completed_jobs[index] = *job;
            }
        }
    }

    (updated_queue, updated_status, maintenance_set, completed_jobs)
}
