func generate_prime_numbers(n int) (primeNumbers []int, err error) {
	if n <= 0 {
		return nil, errors.New("n must be a positive integer")
	}

	// Initialize a boolean array, prime, of size n+1
	prime := make([]bool, n+1)
	for i := 0; i <= n; i++ {
		prime[i] = true
	}

	// 0 and 1 are not prime numbers
	prime[0] = false
	prime[1] = false

	// Iterate from 2 to sqrt(n)
	for i := 2; i <= int(math.Sqrt(float64(n))) + 1; i++ {
		// If i is a prime number, mark its multiples as non-prime
		if prime[i] {
			for j := i * i; j <= n; j += i {
				prime[j] = false
			}
		}
	}

	// Collect all prime numbers in a slice
	for i := 2; i <= n; i++ {
		if prime[i] {
			primeNumbers = append(primeNumbers, i)
		}
	}

	return
}

func main() {
	primeNumbers, err := generate_prime_numbers(30)
	if err != nil {
		fmt.Println(err)
	} else {
		fmt.Println("Prime numbers:", primeNumbers)
	}
