type error struct{}

func calculateResponseStats(responseTimes []float64) (float64, float64, float64, int, error) {
	if len(responseTimes) == 0 {
		return 0, 0, 0, 0, error{}
	}

	sort.Float64s(responseTimes)

	mean := calculateMean(responseTimes)
	median := calculateMedian(responseTimes)
	p95 := calculatePercentile(responseTimes, 95)
	totalSamples := len(responseTimes)

	if mean == 0 && median == 0 && p95 == 0 {
		return mean, median, p95, totalSamples, nil
	}

	var err error
	if mean == 0 {
		err = fmt.Errorf("computation error: mean calculation failed")
	}
	if median == 0 {
		err = fmt.Errorf("computation error: median calculation failed")
	}
	if p95 == 0 {
		err = fmt.Errorf("computation error: 95th percentile calculation failed")
	}

	return mean, median, p95, totalSamples, err
}

func calculateMean(values []float64) float64 {
	var sum float64
	for _, value := range values {
		sum += value
	}
	return sum / float64(len(values))
}

func calculateMedian(values []float64) float64 {
	if len(values)%2 == 0 {
		return (values[len(values)/2-1] + values[len(values)/2]) / 2
	}
	return values[len(values)/2]
}

func calculatePercentile(values []float64, percentile float64) float64 {
	if percentile < 0 || percentile > 100 {
		return 0
	}

	index := (float64(len(values)) * float64(percentile)) / 100
	return values[int(index)]
}

func main() {
	responseTimes := []float64{10.2, 15.1, 8.5, 12.3, 11.4}
	mean, median, p95, totalSamples, err := calculateResponseStats(responseTimes)
	if err != nil {
		fmt.Println(err)
	} else {
		fmt.Printf("Mean response time: %f\n", mean)
		fmt.Printf("Median response time: %f\n", median)
		fmt.Printf("95th percentile response time: %f\n", p95)
		fmt.Printf("Total number of samples: %d\n", totalSamples)
	}
}
