	cached := false
	for _, header := range response.Headers {
		if strings.HasPrefix(header, "Cache-Control") {
			// Check if the response can be cached
			if strings.Contains(header, "no-cache") || strings.Contains(header, "no-store") {
				cached = false
			} else {
				cached = true
			}
			break
		}
	}

	return statusCode, message, cached
