func find_matching_filenames(directory string, pattern string) (matchedFilenames []string, matchedCount int, err error) {
    re := regexp.MustCompile(pattern)
    files, err := ioutil.ReadDir(directory)
    if err != nil {
        return nil, 0, err
    }

    matchedFilenames = make([]string, 0)
    for _, file := range files {
        if file.IsDir() {
            continue
        }
        filename := file.Name()
        if re.MatchString(filename) {
            matchedFilenames = append(matchedFilenames, filename)
            matchedCount++
        }
    }

    return matchedFilenames, matchedCount, nil
}

func main() {
    directory := "./example"
    pattern := ".*\\.txt$"
    matchedFilenames, matchedCount, err := find_matching_filenames(directory, pattern)
    if err != nil {
        log.Fatal(err)
    }
    fmt.Println("Matched filenames:", matchedFilenames)
    fmt.Println("Total matched files:", matchedCount)
