import (
    "context"
    "fmt"
    "net"
    "time"
)

func scanHostPorts(hostname string) (string, int, bool) {
    ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
    defer cancel()

    addr, err := net.ResolveTCPAddr("tcp", fmt.Sprintf("%s:80", hostname))
    if err != nil {
        return hostname, 0, false
    }

    conn, err := net.DialContext(ctx, "tcp", addr)
    if err != nil {
        return hostname, 0, false
    }
    conn.Close()

    var firstOpenPort int
    for i := 1; i <= 65535; i++ {
        ctx, cancel := context.WithTimeout(context.Background(), 1*time.Second)
        defer cancel()

        conn, err := net.DialContext(ctx, "tcp", fmt.Sprintf("%s:%d", hostname, i))
        if err != nil {
            continue
        }
        defer conn.Close()

        if conn.RemoteAddr().String() == fmt.Sprintf("%s:%d", hostname, i) {
            conn.Close()
            firstOpenPort = i
            return hostname, firstOpenPort, true
        }
    }

    return hostname, 0, false
}

func main() {
    hostname := "example.com"
    result := scanHostPorts(hostname)
    fmt.Println(result)
}
