use std::collections::{BTreeMap, HashSet, VecDeque, LinkedList, Vec};
use std::collections::btree_set::BTreeSet;
use std::collections::deque::DoubleEndedDeque;
use std::collections::smallvec::SmallVec;

fn build_indexing_pipeline(documents: Vec<String>, keywords: Vec<String>) -> (BTreeMap<String, Vec<usize>>, VecDeque<String>, HashSet<String>, SmallVec<[usize; 10]>, LinkedList<String>) {
    let mut index = BTreeMap::new();
    let mut queue = VecDeque::new();
    let mut indexed_docs = HashSet::new();
    let mut buffer = SmallVec::new();
    let mut log = LinkedList::new();

    for (i, document) in documents.into_iter().enumerate() {
        indexed_docs.insert(i);
        queue.push_back(document.clone());
        log.push_back(String::from(format!("Processing document {}: {}", i, document)));

        for keyword in keywords {
            let positions: Vec<usize> = document
                .split_whitespace()
                .map(|word| word.len())
                .filter(|&pos| word == keyword)
                .collect();

            if positions.is_empty() {
                log.push_back(String::from(format!("Document {}: {}", i, keyword)));
                log.push_back(String::from(format!("Keyword {} not found in document {}", keyword, i)));
            } else {
                if let Some(existing_positions) = index.get_mut(&keyword) {
                    existing_positions.extend(positions);
                    existing_positions.sort();
                } else {
                    index.insert(keyword.clone(), positions);
                }
            }
        }

        buffer.extend(positions);
    }

    for pos in buffer.drain(..) {
        if let Some(existing_positions) = index.get_mut(&keyword_at_position(pos)) {
            existing_positions.push(pos);
            existing_positions.sort();
        } else {
            index.insert(keyword_at_position(pos).clone(), vec![pos]);
        }
    }

    (index, queue, indexed_docs, buffer, log)
}

fn keyword_at_position(position: usize) -> String {
    let mut keyword = String::new();
    for word in documents[0].split_whitespace() {
        if word.len() == position {
            keyword.push_str(word);
        } else {
            break;
        }
    }
    keyword
}
