use std::collections::{BTreeMap, BTreeSet, VecDeque};
use std::collections::btree_map::Ordering;
use std::iter::FromIterator;

#[derive(Debug)]
struct Transaction {
    account_id: String,
    amount: f64,
    status: String,
}

impl Transaction {
    fn new(account_id: String, amount: f64) -> Self {
        Transaction {
            account_id,
            amount,
            status: "pending".to_string(),
        }
    }
}

fn manage_account_transactions(transactions: Vec<Transaction>) -> (VecDeque<Transaction>, BTreeMap<String, f64>, BTreeSet<String>, Vec<Transaction>) {
    let mut failed_transactions = VecDeque::new();
    let mut account_balances = BTreeMap::new();
    let mut review_accounts = BTreeSet::new();
    let mut processed_transactions = Vec::new();

    for transaction in transactions {
        let balance = account_balances.entry(transaction.account_id.clone()).or_insert(0.0);
        if transaction.amount < 0.0 {
            if *balance < -transaction.amount {
                failed_transactions.push_back(transaction);
                *balance -= transaction.amount;
                transaction.status = "failed".to_string();
            } else {
                *balance -= transaction.amount;
                transaction.status = "successful".to_string();
                processed_transactions.push(transaction);
            }
        } else {
            *balance += transaction.amount;
            transaction.status = "successful".to_string();
            processed_transactions.push(transaction);
        }

        if transaction.amount.abs() > 1000.0 && transaction.amount > 0.0 {
            review_accounts.insert(transaction.account_id.clone());
        }
    }

    (failed_transactions, account_balances, review_accounts, processed_transactions)
}

fn main() {
    let transactions = vec![
        Transaction::new("account1".to_string(), 1000.0),
        Transaction::new("account2".to_string(), -500.0),
        Transaction::new("account3".to_string(), 2000.0),
        Transaction::new("account4".to_string(), -1500.0),
    ];

    let (failed_transactions, account_balances, review_accounts, processed_transactions) =
        manage_account_transactions(transactions);

    println!("Failed Transactions: {:?}", failed_transactions);
    println!("Account Balances: {:?}", account_balances);
    println!("Review Accounts: {:?}", review_accounts);
    println!("Processed Transactions: {:?}", processed_transactions);
}
