use std::sync::Arc;

fn update_inventory(mut input_data: Vec<(String, i32)>) -> (HashMap<String, i32>, BTreeSet<String>, Arc<Vec<(String, i32)>>) {
    let mut inventory = HashMap::new();
    let mut out_of_stock = BTreeSet::new();
    let mut incoming_products = Vec::new();

    for (product_id, quantity_change) in input_data {
        let current_quantity = inventory.entry(product_id.clone()).or_insert(0);

        *current_quantity += quantity_change;

        if *current_quantity <= 0 {
            out_of_stock.insert(product_id);
        } else if quantity_change > 0 {
            incoming_products.push((product_id, quantity_change));
        }
    }

    (inventory, out_of_stock, Arc::new(incoming_products))
}
